('business:3-7-employment-law:match:559779e7', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Employment Law”?", "options": ["A legal agreement between an employer and an employee, formed when a job offer is accepted.", "A written document detailing the main terms of employment that must be given to employees on or before their first day of work.", "Treating one worker differently from another for no acceptable reason.", "Regulations and rules put in place to protect workers from employers who may treat them unfairly."]}'::jsonb, '{"answer": 3, "explain": "“Employment Law” means: Regulations and rules put in place to protect workers from employers who may treat them unfairly."}'::jsonb),
('business:3-7-employment-law:match:269d3b08', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Contract of Employment”?", "options": ["A written document detailing the main terms of employment that must be given to employees on or before their first day of work.", "Treating one worker differently from another for no acceptable reason.", "A legal agreement between an employer and an employee, formed when a job offer is accepted.", "An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace."]}'::jsonb, '{"answer": 2, "explain": "“Contract of Employment” means: A legal agreement between an employer and an employee, formed when a job offer is accepted."}'::jsonb),
('business:3-7-employment-law:match:023ea78e', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Statement of Employment Particulars”?", "options": ["Treating one worker differently from another for no acceptable reason.", "An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace.", "A law limiting workers to an average of 48 hours per week over a 17-week period.", "A written document detailing the main terms of employment that must be given to employees on or before their first day of work."]}'::jsonb, '{"answer": 3, "explain": "“Statement of Employment Particulars” means: A written document detailing the main terms of employment that must be given to employees on or before their first day of work."}'::jsonb),
('business:3-7-employment-law:match:d194790f', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Discrimination”?", "options": ["An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace.", "A law limiting workers to an average of 48 hours per week over a 17-week period.", "Treating one worker differently from another for no acceptable reason.", "The amount of paid leave a worker is legally entitled to — 5.6 weeks per year."]}'::jsonb, '{"answer": 2, "explain": "“Discrimination” means: Treating one worker differently from another for no acceptable reason."}'::jsonb),
('business:3-7-employment-law:match:a3a2a077', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Equality Act 2010”?", "options": ["A law limiting workers to an average of 48 hours per week over a 17-week period.", "The amount of paid leave a worker is legally entitled to — 5.6 weeks per year.", "An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace.", "A panel that hears cases where employment laws may have been broken and decides in favour of the employer or employee."]}'::jsonb, '{"answer": 2, "explain": "“Equality Act 2010” means: An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace."}'::jsonb),
('business:3-7-employment-law:match:4f127e78', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Working Time Directive”?", "options": ["A law limiting workers to an average of 48 hours per week over a 17-week period.", "The amount of paid leave a worker is legally entitled to — 5.6 weeks per year.", "A panel that hears cases where employment laws may have been broken and decides in favour of the employer or employee.", "An employee organisation that exists to represent the interests of its members, including providing legal support."]}'::jsonb, '{"answer": 0, "explain": "“Working Time Directive” means: A law limiting workers to an average of 48 hours per week over a 17-week period."}'::jsonb),
('business:3-7-employment-law:match:6c53de90', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Holiday Entitlement”?", "options": ["The amount of paid leave a worker is legally entitled to — 5.6 weeks per year.", "A panel that hears cases where employment laws may have been broken and decides in favour of the employer or employee.", "An employee organisation that exists to represent the interests of its members, including providing legal support.", "The voluntary choice by a worker to work more than the 48-hour average weekly limit."]}'::jsonb, '{"answer": 0, "explain": "“Holiday Entitlement” means: The amount of paid leave a worker is legally entitled to — 5.6 weeks per year."}'::jsonb),
('business:3-7-employment-law:match:aaaa6baa', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Employment Tribunal”?", "options": ["A panel that hears cases where employment laws may have been broken and decides in favour of the employer or employee.", "An employee organisation that exists to represent the interests of its members, including providing legal support.", "The voluntary choice by a worker to work more than the 48-hour average weekly limit.", "The legal requirement that men and women must be paid the same when doing work of equal value."]}'::jsonb, '{"answer": 0, "explain": "“Employment Tribunal” means: A panel that hears cases where employment laws may have been broken and decides in favour of the employer or employee."}'::jsonb),
('business:3-7-employment-law:match:b24ec9b8', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade Union”?", "options": ["The voluntary choice by a worker to work more than the 48-hour average weekly limit.", "The legal requirement that men and women must be paid the same when doing work of equal value.", "An employee organisation that exists to represent the interests of its members, including providing legal support.", "A neutral policy or rule that disproportionately disadvantages members of a particular protected group."]}'::jsonb, '{"answer": 2, "explain": "“Trade Union” means: An employee organisation that exists to represent the interests of its members, including providing legal support."}'::jsonb),
('business:3-7-employment-law:match:de68e48f', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Opt Out”?", "options": ["The voluntary choice by a worker to work more than the 48-hour average weekly limit.", "The legal requirement that men and women must be paid the same when doing work of equal value.", "A neutral policy or rule that disproportionately disadvantages members of a particular protected group.", "Regulations and rules put in place to protect workers from employers who may treat them unfairly."]}'::jsonb, '{"answer": 0, "explain": "“Opt Out” means: The voluntary choice by a worker to work more than the 48-hour average weekly limit."}'::jsonb),
('business:3-7-employment-law:match:dace51ef', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Equal Pay”?", "options": ["A neutral policy or rule that disproportionately disadvantages members of a particular protected group.", "Regulations and rules put in place to protect workers from employers who may treat them unfairly.", "A legal agreement between an employer and an employee, formed when a job offer is accepted.", "The legal requirement that men and women must be paid the same when doing work of equal value."]}'::jsonb, '{"answer": 3, "explain": "“Equal Pay” means: The legal requirement that men and women must be paid the same when doing work of equal value."}'::jsonb),
('business:3-7-employment-law:match:a647eaf4', 'business', 'business:3-7-employment-law', '3.7 Employment Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Indirect Discrimination”?", "options": ["A neutral policy or rule that disproportionately disadvantages members of a particular protected group.", "Regulations and rules put in place to protect workers from employers who may treat them unfairly.", "A legal agreement between an employer and an employee, formed when a job offer is accepted.", "A written document detailing the main terms of employment that must be given to employees on or before their first day of work."]}'::jsonb, '{"answer": 0, "explain": "“Indirect Discrimination” means: A neutral policy or rule that disproportionately disadvantages members of a particular protected group."}'::jsonb),
('business:4-1-production-processes:exam:45f7dcb6', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Exam Paper Q1", "question": "Which is an advantage for a manufacturer of using robotics? [1 mark]", "options": ["Greater productivity", "Initial investment cost", "Operatives will require training", "Will not break down"], "hint": "Think about what robots do BETTER than humans — not what they cost or what goes wrong with them.", "starter": "The advantage of using robotics for a manufacturer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Greater productivity</h5><p><strong>Why A is correct:</strong> Robots can work 24/7 without breaks, producing more output in less time and with greater consistency than human workers — this directly increases productivity.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Initial investment cost)</strong> — This is a <em>disadvantage</em> of robotics, not an advantage. The upfront cost of buying and installing robots is very high.</li><li><strong>C (Operatives will require training)</strong> — This is also a <em>disadvantage</em>. Workers need to be trained to operate and oversee the robots, which adds to business costs.</li><li><strong>D (Will not break down)</strong> — This is factually <em>incorrect</em>. Machines CAN and do break down — breakdown risk is actually a key disadvantage of using robotics.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:e40a1ea1', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Exam Paper Q5", "question": "Which of the following is NOT a disadvantage of automation? [1 mark]", "options": ["Expensive to buy, so will need to find a way of raising finance", "Machines can break down, disrupting production", "Operatives may need additional training, increasing business costs", "The machinery can be reprogrammed, making production more flexible"], "hint": "Look for the option that is actually a BENEFIT of automation, not a drawback.", "starter": "The option that is NOT a disadvantage of automation is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — The machinery can be reprogrammed, making production more flexible</h5><p><strong>Why D is correct:</strong> Being reprogrammable and flexible is an ADVANTAGE of automation — it allows the business to produce a variety of products without rebuilding its production line.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Expensive to buy)</strong> — This IS a disadvantage. Technology requires high upfront capital investment, which the business must find a way to finance.</li><li><strong>B (Machines can break down)</strong> — This IS a disadvantage. Breakdown risk is a key concern, especially in flow production where one failure can halt the entire line.</li><li><strong>C (Training costs)</strong> — This IS a disadvantage. Existing workers need to be retrained to work with new technology, which increases costs.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:e9e3f51b', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Exam Paper Q8", "question": "A company''s total costs are too high. The finance manager advises that this is being caused by increasing wage costs as the company expands. Which one of the following actions would provide a long-term solution to this problem? [1 mark]", "options": ["Applying for an overdraft", "Automating the production process", "Employing a finance assistant", "Switching to job production"], "hint": "The problem is rising WAGE costs long-term. Which option directly and permanently reduces the need for workers?", "starter": "The best long-term solution to high wage costs is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Automating the production process</h5><p><strong>Why B is correct:</strong> Automation replaces labour with computer-controlled machinery. This directly reduces the number of workers needed, permanently lowering wage costs in the long term.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Applying for an overdraft)</strong> — An overdraft provides short-term finance to cover a cash shortage. It must be repaid with interest and does nothing to solve the underlying wage cost problem.</li><li><strong>C (Employing a finance assistant)</strong> — This would ADD to wage costs, making the problem worse, not better.</li><li><strong>D (Switching to job production)</strong> — Job production typically requires highly skilled workers who command HIGHER wages. This would increase wage costs, not reduce them.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:3a443dbf', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Exam Paper Q9", "question": "Breakfast biscuits are becoming increasingly popular. HealthBisc Ltd predicts that in future years it will have difficulty producing enough breakfast biscuits to keep up with demand. Which one of the following actions could help HealthBisc Ltd deal with this problem? [1 mark]", "options": ["Automate the production process", "Improve its after-sales service", "Reduce its prices", "Switch to job production"], "hint": "The problem is production CAPACITY — not enough output to meet demand. Which option increases the amount that can be produced?", "starter": "The best action to increase production capacity is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Automate the production process</h5><p><strong>Why A is correct:</strong> Automation allows machines to work 24/7, dramatically increasing the rate and volume of production to meet higher levels of demand. This directly solves the capacity problem.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Improve after-sales service)</strong> — After-sales service relates to customer experience after purchase. It does nothing to increase production output or capacity.</li><li><strong>C (Reduce its prices)</strong> — Reducing prices would likely increase demand even further, making the production shortfall problem worse, not better.</li><li><strong>D (Switch to job production)</strong> — Job production makes items individually, one at a time. This would dramatically REDUCE output, making it impossible to meet the high levels of demand.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:7ebf4bff', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Exam Paper Q10", "question": "An entrepreneur makes individual handmade prom dresses to order. What method of production does the entrepreneur use? [1 mark]", "options": ["Automated", "Batch", "Flow", "Job"], "hint": "The key word is ''individual'' and ''to order''. Which method makes each product one at a time to a specific customer''s requirements?", "starter": "The method of production used by the entrepreneur is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Job production</h5><p><strong>Why D is correct:</strong> Job production involves making each product individually to meet the exact requirements of a specific customer order. Each prom dress is unique and made one at a time — this is the definition of job production.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Automated)</strong> — Automation involves computer-controlled machinery. This handmade dress is made by a skilled person, not a machine.</li><li><strong>B (Batch)</strong> — Batch production would mean making a group of the same dress style, then switching to a different style. Each dress here is individual, not part of a batch.</li><li><strong>C (Flow)</strong> — Flow production continuously makes the same product in large quantities on an assembly line. Individual handmade dresses are the opposite of this.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:daad4ea7', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Textbook Practice MCQ 1", "question": "Jenny Carson makes and ices wedding cakes. Which method of production is she likely to use? [1 mark]", "options": ["Job production", "Batch production", "Flow production", "Robotic production"], "hint": "Each wedding cake is unique and made to a specific customer''s order. Which method makes one product at a time?", "starter": "The method of production Jenny Carson is most likely to use is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Job production</h5><p><strong>Why A is correct:</strong> Each wedding cake is unique and made individually to the specific order of the customer. This is the definition of job production — products are made individually, often requiring skilled labour and producing high-quality, bespoke items.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Batch production)</strong> — This would mean making a group of the same type of cake, then switching to a different type. Jenny makes each cake uniquely to order, not in batches.</li><li><strong>C (Flow production)</strong> — Flow production makes the same product continuously in large quantities. Individual, unique wedding cakes cannot be mass-produced on an assembly line.</li><li><strong>D (Robotic production)</strong> — Robotic production is not one of the three official OCR production methods. The skill and artistry involved in icing a wedding cake also requires human craftsmanship.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:6855e0d0', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Textbook Practice MCQ 2", "question": "Warburton''s bakery uses batch production to make its bread. Which of the following is a disadvantage to Warburton''s of using batch production to make its bread? [1 mark]", "options": ["The costs of production are lower than using other methods.", "It can meet the demand for different types of bread from different customers.", "It may have to reduce the different types of bread that it can offer.", "It can make bread to order so the bread does not need to be stored."], "hint": "Look for the option that is a PROBLEM for Warburton''s — not a benefit. Think about what batch production prevents or limits.", "starter": "The disadvantage of batch production for Warburton''s is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — It may have to reduce the different types of bread that it can offer.</h5><p><strong>Why C is correct:</strong> If production switching becomes too complex or costly, Warburton''s may be forced to limit the number of different bread varieties it produces — reducing customer choice and potentially losing sales to competitors with wider ranges.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Lower costs)</strong> — Lower costs is an ADVANTAGE of batch production, as specialist machinery can be used and production runs are efficient.</li><li><strong>B (Meets varied demand)</strong> — Meeting the needs of different customers is an ADVANTAGE — it is the main reason bakeries use batch production.</li><li><strong>D (Made to order / no storage needed)</strong> — Making bread to specific orders, reducing storage costs, is an ADVANTAGE of batch production.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:223b2430', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Textbook Practice MCQ 3", "question": "Which of the following is not an example of automation? [1 mark]", "options": ["Beer bottles are labelled by a machine when they pass it on the production line.", "The hand-making of a wedding dress.", "A business has sensors on its doors to make them open when someone approaches.", "Customers of Vauxhall Motors can configure and order their own car online which is added to production without any further input."], "hint": "Automation means a computer or machine does the task with NO human direct control. Which option requires a skilled human to do the work?", "starter": "The option that is NOT an example of automation is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The hand-making of a wedding dress.</h5><p><strong>Why B is correct:</strong> Hand-making a wedding dress is done by a skilled human worker using their own judgement, creativity, and craft skills. There is no machine or computer controlling the process. This is an example of job production, not automation.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> — Beer bottles passing a labelling machine is automation: the machine applies labels without a human controlling it at each step.</li><li><strong>C</strong> — Door sensors that detect people and open automatically are automation — the computer/sensor controls the door without human input.</li><li><strong>D</strong> — The Vauxhall Motors example is automation: the online order goes directly into the production system without any further human input, which is a form of computer-controlled automation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:exam:ba858a28', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'exam', 'mcq', 1, '{"num": "Textbook Practice MCQ 4", "question": "Which of these statements is false? [1 mark]", "options": ["Modern businesses do not use job production.", "Flow production uses machines only, no workers are required at all.", "Batch production is often used by bakeries to make different kinds of bread and cakes.", "Using flow production usually results in lower unit costs than using job production."], "hint": "Think carefully — TWO of these statements are false, but which one is the MOST clearly false and directly contradicts what you''ve learned?", "starter": "The statement that is false is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Modern businesses do not use job production.</h5><p><strong>Why A is correct (i.e., A is FALSE):</strong> Many modern businesses use job production — from large construction projects like Crossrail, to hand-crafted furniture makers, to bespoke advertising campaigns. This statement is factually incorrect.</p><p><strong>Note on the other options:</strong></p><ul><li><strong>B</strong> is also false (flow production still requires workers to oversee machines), but A is the intended answer as it directly targets a common student misconception.</li><li><strong>C</strong> is TRUE — bakeries like Warburton''s and Crown Paints use batch production.</li><li><strong>D</strong> is TRUE — flow production benefits from economies of scale, giving lower unit costs than job production.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-1-production-processes:mcq:aeae5682', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which is an advantage for a manufacturer of using robotics?", "options": ["Initial investment cost", "Operatives will require training", "Greater productivity", "Will not break down"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: A — Greater productivity. Robots can work 24/7 without breaks, producing more output in less time and at greater consistency. B (initial investment) and C (training costs) are both disadvantages. D is incorrect — machines CAN and do break down, which is actually a key disadvantage of robotics."}'::jsonb),
('business:4-1-production-processes:mcq:65434983', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Jenny Carson makes and ices wedding cakes individually to order. Which method of production is she most likely to use?", "options": ["Job production", "Batch production", "Robotic production", "Flow production"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — Job production. Each wedding cake is unique and made individually to the customer''s specific requirements — the definition of job production. Batch (B) would mean switching between types; flow (C) means mass-producing identical cakes on a line; robotic production (D) is not one of the three official OCR production methods."}'::jsonb),
('business:4-1-production-processes:mcq:81c7e163', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Warburton''s bakery uses batch production to make its bread. Which of the following is a disadvantage of this approach?", "options": ["The costs of production are lower than using other methods.", "It can meet the demand for different types of bread from different customers.", "It may have to reduce the different types of bread that it can offer.", "It can make bread to order so the bread does not need to be stored."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. If managing too many product switches becomes too costly or complex, Warburton''s may be forced to limit its product range — a disadvantage. Options A, B, and D are all advantages of batch production: lower costs (A), meeting varied demand (B), and made-to-order reducing storage (D)."}'::jsonb),
('business:4-1-production-processes:mcq:20f1b85c', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT an example of automation?", "options": ["Beer bottles are labelled by a machine when they pass it on the production line.", "The hand-making of a wedding dress.", "A business has sensors on its doors to make them open when someone approaches.", "Customers of Vauxhall Motors can configure and order a car online which is added to production without any further input."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Hand-making a wedding dress is job production — carried out by a skilled human worker, not a computer-controlled machine. All other options describe processes controlled automatically by machines or computers with no direct human operation."}'::jsonb),
('business:4-1-production-processes:mcq:2a75cf14', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which of these statements is FALSE?", "options": ["Modern businesses do not use job production.", "Flow production uses machines only, no workers are required at all.", "Batch production is often used by bakeries to make different kinds of bread and cakes.", "Using flow production usually results in lower unit costs than using job production."]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. It is FALSE that modern businesses do not use job production. Many modern businesses — including those running large construction projects like Crossrail — use job production. C and D are both true. B is also false (flow production still requires workers to oversee machines), but A is the most clearly false and is the intended answer."}'::jsonb),
('business:4-1-production-processes:mcq:cca42c0d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a disadvantage of automation?", "options": ["Expensive to buy, so will need to find a way of raising finance", "Machines can break down, disrupting production", "Operatives may need additional training, increasing business costs", "The machinery can be reprogrammed, making production more flexible"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Being reprogrammable and flexible is an ADVANTAGE of automation, not a disadvantage. Options A (high cost to buy), B (breakdown risk), and C (training costs) are all genuine disadvantages of investing in automation technology."}'::jsonb),
('business:4-1-production-processes:mcq:4819355e', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "A company''s total costs are too high due to increasing wage costs as it expands. Which action would provide a long-term solution?", "options": ["Applying for an overdraft", "Automating the production process", "Employing a finance assistant", "Switching to job production"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Automating the production process. Automation replaces labour with machines, directly reducing wage costs long-term. An overdraft (A) only provides short-term finance and must be repaid. Employing a finance assistant (C) would add costs. Switching to job production (D) typically increases labour costs as it demands skilled workers."}'::jsonb),
('business:4-1-production-processes:mcq:4acf19b4', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "HealthBisc Ltd predicts it will struggle to produce enough breakfast biscuits to meet growing demand. Which action could best help?", "options": ["Automate the production process", "Improve its after-sales service", "Reduce its prices", "Switch to job production"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — Automate the production process. Automation enables machines to work 24/7, significantly increasing output and productivity to meet higher demand. Improving after-sales service (B) and reducing prices (C) are marketing decisions that do not increase production capacity. Switching to job production (D) would actually decrease output as items are made individually."}'::jsonb),
('business:4-1-production-processes:mcq:88c167ab', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "An entrepreneur makes individual handmade prom dresses to order. What method of production does the entrepreneur use?", "options": ["Batch", "Automated", "Flow", "Job"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Job production. Each dress is made individually to a specific customer''s order — the definition of job production. Automated (A) means computer-controlled machinery. Batch (B) would mean making a group of dresses of the same style then switching to another. Flow (C) means continuous mass production of identical items."}'::jsonb),
('business:4-1-production-processes:mcq:d92f1978', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which of the following is a characteristic of flow production?", "options": ["Products are made individually to customer specifications", "Production is switched between different product types", "Goods are produced continuously using an assembly line", "High labour costs due to the need for skilled workers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Flow production uses a continuous assembly line to make large quantities of the same product without stopping. Option A describes job production. Option B describes batch production. Option D describes job production, which requires skilled and therefore expensive labour."}'::jsonb),
('business:4-1-production-processes:mcq:2f5482da', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of flow production?", "options": ["Unit costs per product are very high", "If the production line breaks down, the entire factory may shut down", "Machinery cannot be used in flow production", "Products made using flow production are always of poor quality"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A major risk of flow production is that a single breakdown on the assembly line can halt the entire factory, causing huge financial losses. Option A is wrong — unit costs are actually LOW in flow production. Option C is wrong — machinery is central to flow production. Option D is incorrect — quality can still be high and consistent in flow production."}'::jsonb),
('business:4-1-production-processes:mcq:2a9a62d1', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'mcq', 'mcq', 1, '{"question": "Crown Paints makes different types and colours of paint in its factory. Which method of production does Crown Paints use?", "options": ["Robotic production", "Flow production", "Batch production", "Job production"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: B — Batch production. Crown Paints makes one type and colour of paint, fills and labels the tins, then switches production to a different type or colour. This is the definition of batch production — switching between different products. Job (A) makes one unique item at a time. Flow (C) makes the same product continuously. Robotic (D) is not one of the three main production methods."}'::jsonb),
('business:4-1-production-processes:tf:6911106f', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Modern businesses do not use job production."}'::jsonb, '{"answer": false, "explain": "FALSE. Many modern businesses still use job production. Large-scale projects like the Crossrail railway in London are examples of job production. It is a common misconception that job production is only for small artisan businesses — it is not."}'::jsonb),
('business:4-1-production-processes:tf:c7ee2998', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Goods produced by flow production are usually made to suit the needs of individual customers."}'::jsonb, '{"answer": false, "explain": "FALSE. Flow production makes standardised, identical products in large quantities for the mass market. It is JOB production that creates products tailored to individual customer needs."}'::jsonb),
('business:4-1-production-processes:tf:a5eaad06', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Flow production is suited to large-scale production."}'::jsonb, '{"answer": true, "explain": "TRUE. Flow production is specifically designed to produce very large quantities of the same product continuously. This is what makes it suited to mass markets and high-demand products like cars and baked beans."}'::jsonb),
('business:4-1-production-processes:tf:24df7a36', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Working in a batch production process can be repetitive and boring for workers."}'::jsonb, '{"answer": true, "explain": "TRUE. Because batch production involves repeating the same tasks many times within each batch, workers can find the work monotonous. This can negatively affect motivation and productivity."}'::jsonb),
('business:4-1-production-processes:tf:a9d0a5b3', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Flow production does not require any workforce at all."}'::jsonb, '{"answer": false, "explain": "FALSE. Flow production does still require workers — they oversee the machines, perform quality checks, manage supply chains, and complete tasks not fully automated. Technology reduces but rarely eliminates the need for workers entirely."}'::jsonb),
('business:4-1-production-processes:tf:da958ae3', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Job production workers are often highly skilled."}'::jsonb, '{"answer": true, "explain": "TRUE. Job production requires skilled labour because each product is unique and made to a high standard. This is a key reason why the costs of job production are high — skilled workers command higher wages."}'::jsonb),
('business:4-1-production-processes:tf:2d361cb2', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Goods produced by job production are usually high quality."}'::jsonb, '{"answer": true, "explain": "TRUE. Because each item is individually made with care and expertise to meet a specific customer''s requirements, job production typically produces high-quality, bespoke products. This justifies the premium prices charged."}'::jsonb),
('business:4-1-production-processes:tf:e3264a3e', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Many dangerous processes are best carried out by automated machinery."}'::jsonb, '{"answer": true, "explain": "TRUE. Automation is ideal for dangerous environments. Robots were sent into the Fukushima nuclear site in Japan after the 2014 explosion because it was too dangerous for humans to enter. Machines can also do other hazardous tasks that workers may be unwilling or unable to do safely."}'::jsonb),
('business:4-1-production-processes:tf:d1576835', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Supermarket in-store bakeries use the batch production method."}'::jsonb, '{"answer": true, "explain": "TRUE. In-store bakeries make a batch of one type of bread or pastry, then switch to produce a different type. This is the definition of batch production — making one product type, then switching to another."}'::jsonb),
('business:4-1-production-processes:tf:5f11522d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "It is cheap to set up a flow manufacturing process."}'::jsonb, '{"answer": false, "explain": "FALSE. Setting up a flow production line is very expensive. The machinery, conveyor systems, and factory layout all require enormous capital investment — this is one of the key disadvantages of flow production."}'::jsonb),
('business:4-1-production-processes:tf:b3648870', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Automation can increase the flexibility of production because machines can be reprogrammed."}'::jsonb, '{"answer": true, "explain": "TRUE. Unlike fixed machinery, computer-controlled automated machines can be reprogrammed to produce a variety of products without rebuilding the production line. This is a key advantage of automation over older fixed machinery."}'::jsonb),
('business:4-1-production-processes:tf:a98f0417', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tf', 'tf', 1, '{"question": "Job production is exclusively used by small businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. This is a very common misconception. Job production is used by businesses of all sizes. The Crossrail project, large ship-building companies, and major advertising agencies all use job production on a very large scale. The method refers to HOW something is made, not the size of the business."}'::jsonb),
('business:4-1-production-processes:learn:22a2f02c', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the <strong>official OCR definitions</strong> you must know precisely for the exam. Learn them word for word.</p>\n    <ul>\n      <li><strong>Job Production:</strong> Is the process of production where products are made individually.</li>\n      <li><strong>Batch Production:</strong> Is the process of production where one type of product is made and then production is switched to make a different product.</li>\n      <li><strong>Flow Production:</strong> Is production of one product that takes place continuously using a production or assembly line. This is sometimes called mass production.</li>\n      <li><strong>Automation:</strong> Is a production process involving machinery that is not controlled by a person but usually controlled by a computer.</li>\n      <li><strong>Robotics:</strong> Is the use of robots in the process of production.</li>\n      <li><strong>Production Processes:</strong> Are the three methods or processes of production – job, batch and flow.</li>\n    </ul>", "question": "What is the key difference between automation and robotics?", "options": ["They mean the same thing; textbooks use the terms interchangeably", "Automation is the broader term; robotics is one specific type of it", "Robotics is broader; automation means only human-shaped machines", "Automation always needs a robot; robotics never involves automation"]}'::jsonb, '{"answer": 1, "explain": "Automation covers any computer-controlled production process. Robotics is a specific subset of automation where programmable robots perform tasks — all robotics is automation, but not all automation involves robots."}'::jsonb),
('business:4-1-production-processes:learn:02dbb163', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Job Production", "reading": "<p><strong>Job production</strong> involves producing each product individually. Each item is unique and made to meet the exact requirements of an individual customer. Products made this way are often called <strong>bespoke</strong>.</p>\n    <p><strong>Examples of job production:</strong></p>\n    <ul>\n      <li>Building a bridge, factory, or shopping centre</li>\n      <li>Craft production: paintings, pottery, sculptures</li>\n      <li>Tailoring hand-made dresses and suits</li>\n      <li>Creating an advertising campaign</li>\n      <li>Building ships and aircraft</li>\n      <li>Taking wedding photographs or making a film</li>\n      <li>Hand-crafted furniture (e.g., Louis le Glas at the Coppice Co-op)</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>High quality:</strong> Products are usually high quality as they are made with great care and skill to meet the specific needs of the customer.</div>\n    <div class=\"pro-item\"><strong>Bespoke products:</strong> Products can be made to exactly meet the needs of individual customers, giving a strong competitive edge and justifying premium prices.</div>\n    <div class=\"pro-item\"><strong>Worker satisfaction:</strong> Workers often get more satisfaction from working on something until it is finished, which can improve motivation and reduce absenteeism.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>High production costs:</strong> Costs of production will be high as each product is individually crafted, meaning higher prices for customers.</div>\n    <div class=\"con-item\"><strong>High labour costs:</strong> Labour costs may be high because job production often requires skilled labour who command higher wages.</div>\n    <div class=\"con-item\"><strong>Slow output:</strong> Production is slow — only one item is made at a time, limiting the ability to meet large-scale or mass-market demand.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: The Coppice Co-op Ltd</h4>\n    <p>Louis Le Glas is a skilled woodworker at the Coppice Co-op Ltd in Carnforth, Lancashire. He designs and carves unique pieces of furniture, and each piece is one-of-a-kind. Customers can have furniture made exactly as they want it — true bespoke production. The business is also fiercely concerned about sustainable production, managing woodlands through a process called coppicing.</p>\n    <p><strong>Takeaway:</strong> Job production allows Louis to charge premium prices because each piece is unique. However, it limits how many products he can make, keeping the scale of the business small.</p>\n    </div>", "question": "Why does job production typically result in higher prices for customers?", "options": ["Because the products are sold through supermarket chains at a discount", "Because each product is individually crafted, needing skilled time", "Because businesses using job production always make huge profits", "Because flow production always costs more to run than job production"]}'::jsonb, '{"answer": 1, "explain": "Job production is labour-intensive and requires skilled workers to make each item individually — both of which drive up costs per unit, which are then passed on through premium prices."}'::jsonb),
('business:4-1-production-processes:learn:33901133', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Batch Production", "reading": "<p><strong>Batch production</strong> involves producing one type of product for a period, then switching to make a different type. The business will switch back to the first product when more is needed. Machinery may need to be re-set between batches.</p>\n    <p><strong>Examples of batch production:</strong></p>\n    <ul>\n      <li>Bakeries making a batch of white bread, then switching to wholemeal</li>\n      <li>Paint manufacturing — different colours and types (e.g., Crown Paints)</li>\n      <li>Clothing manufacturers switching between different garment types</li>\n      <li>Newspapers, books, furniture, and electrical goods</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Meets varied customer needs:</strong> Batches of different goods can be made, allowing a business to offer a range of products to different customer groups.</div>\n    <div class=\"pro-item\"><strong>Made to order:</strong> Batches can be made to meet specific orders, reducing storage costs as goods do not need to be held in stock for long periods.</div>\n    <div class=\"pro-item\"><strong>Specialist machinery:</strong> It may be possible to use specialist machines and automate parts of production, helping to save costs compared to job production.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Switching time and costs:</strong> It takes time to switch production from one batch to another. Machinery may need to be re-set, adding costs and reducing output.</div>\n    <div class=\"con-item\"><strong>Stock holding costs:</strong> It may be necessary to keep stocks of materials ready to switch production. Holding stock is a cash flow problem — money has been paid out but revenue is not yet earned.</div>\n    <div class=\"con-item\"><strong>Repetitive work:</strong> Tasks can be repetitive and boring for workers, which can reduce motivation and increase staff turnover.</div>\n    <div class=\"con-item\"><strong>Less variety than job:</strong> There is usually less product choice for customers compared with job production.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Crown Paints</h4>\n    <p>Crown Paints, based in Darwen, Lancashire, makes a range of paints including silk and matte emulsions, gloss paints, and primers in many colours and shades. The ingredients are mixed to make one type and colour of paint. Once this batch is finished, tins are labelled and filled. The factory then switches to produce a different colour or type of paint entirely.</p>\n    <p><strong>Takeaway:</strong> Batch production lets Crown Paints offer a huge range of colours without needing a permanently separate production line for each one. However, cleaning and resetting equipment between batches costs time and money.</p>\n    </div>", "question": "Why can switching between batches create a cash flow problem for a business?", "options": ["Because the batch machinery always breaks down mid-switch", "Because materials get stocked, so cash goes out before revenue", "Because batch production always needs more staff than flow", "Because holding stock has no effect on cash flow at all"]}'::jsonb, '{"answer": 1, "explain": "Holding stock ties up money — the business has paid for materials but hasn''t yet sold any finished goods made from them, creating a gap between cash going out and cash coming in."}'::jsonb),
('business:4-1-production-processes:learn:30c41f39', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Flow Production", "reading": "<p><strong>Flow production</strong> (also called <strong>mass production</strong>) involves producing one type of product continuously using a production or assembly line. The product moves along a conveyor belt and different workers or machines complete different tasks at each stage. There is no stopping.</p>\n    <p><strong>Examples of flow production:</strong></p>\n    <ul>\n      <li>Car manufacturing — Ford, Jaguar Land Rover (JLR)</li>\n      <li>Heinz baked beans — over 1 billion tins per year at their factory near Wigan</li>\n      <li>Plate glass manufacturing</li>\n      <li>Bottled drinks and canned foods produced at scale</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Large quantities:</strong> Massive amounts can be produced continuously to meet high levels of demand in the mass market.</div>\n    <div class=\"pro-item\"><strong>Low unit costs:</strong> The cost per unit is low because the firm benefits from economies of scale — costs are spread over millions of products.</div>\n    <div class=\"pro-item\"><strong>Machinery keeps costs low:</strong> Heavy use of machinery reduces the need for large numbers of workers and lowers wage bills.</div>\n    <div class=\"pro-item\"><strong>Some flexibility:</strong> Modern computer-controlled machines can be programmed to introduce some design variation into the production run.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Quality concerns:</strong> Mass-produced goods may not always meet the high quality or individuality that some customers expect from premium products.</div>\n    <div class=\"con-item\"><strong>Very expensive to set up:</strong> The initial investment in setting up an assembly line is enormous — a major barrier to entry.</div>\n    <div class=\"con-item\"><strong>Large stock required:</strong> Large stocks of raw materials must be maintained to keep the production line running at all times.</div>\n    <div class=\"con-item\"><strong>Breakdown risk:</strong> If production stops at any point on the line (mechanical failure or strike), the entire factory may shut down — extremely costly.</div>\n    <div class=\"con-item\"><strong>Repetitive work:</strong> Assembly line jobs can be very repetitive and boring, leading to lower motivation and higher staff turnover.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Heinz Baked Beans</h4>\n    <p>Heinz makes its baked beans at a factory just outside Wigan. Over 1 billion tins are made each year using a continuous flow method. The beans are mixed with sauce, put into tins that are sealed, then cooked in ovens. From there, the tins go on to be labelled. This entire process runs every day, throughout the year, without stopping.</p>\n    <p><strong>Takeaway:</strong> Flow production allows Heinz to keep the price of baked beans extremely low by producing at massive scale. However, any breakdown on the production line could halt the entire factory and cost millions in lost output and missed orders.</p>\n    </div>", "question": "How many tins of baked beans does Heinz produce per year at its Wigan factory, and what does this illustrate about flow production?", "options": ["1 million — suits only very small-scale firms", "Over 1 billion — shows massive scale, low unit cost", "100,000 — shows flow is slower than batch overall", "No figure is given anywhere in the study"]}'::jsonb, '{"answer": 1, "explain": "Heinz produces over 1 billion tins per year — a perfect illustration of how flow production enables vast output at low unit costs through economies of scale, running continuously without stopping."}'::jsonb),
('business:4-1-production-processes:learn:bee904c0', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Automation, Computers & Robotics in Production", "reading": "<p>Technology has increasingly been introduced into production. The three key forms are <strong>automation</strong>, <strong>computers</strong>, and <strong>robotics</strong>.</p>\n    <p><strong>Automation</strong> means production is controlled by computer rather than by a human worker. Workers'' roles shift to overseeing the computer systems and checking that production is occurring correctly. Examples include:</p>\n    <ul>\n      <li>Crown Paints — the entire canning process runs automatically, with tins being labelled, filled, weighed, and sealed by machines</li>\n      <li>Autopilot on aircraft and ships</li>\n      <li>Automated banking payments and online transactions</li>\n      <li>School systems automatically sending attendance alerts to parents</li>\n    </ul>\n    <p><strong>Computers</strong> are used across service industries to automate processes previously done by people — online banking (Android Pay, Apple Pay), insurance claims, energy billing, and concert ticket booking.</p>\n    <p><strong>Robotics</strong> is a specific type of automation where a computer programs a robot to carry out specific tasks. Around <strong>65% of robot use</strong> is in car manufacturing (welding, painting, lifting). Robots are also used in:</p>\n    <ul>\n      <li>Food, electronics, plastics, and medical sectors</li>\n      <li>Hotel receptions and hospitals (collecting laundry)</li>\n      <li>Dangerous environments — robots entered the Fukushima nuclear site after the 2014 explosion; humans could not safely do so</li>\n      <li>Surgery — robots assist surgeons with high-precision operations</li>\n    </ul>\n    <p>Thanks to <strong>artificial intelligence (AI)</strong>, robots are increasingly capable of skilled and complex tasks: writing reports, making decisions, and even performing surgery autonomously. The World Economic Forum (2020) predicted that by 2025, technology would eliminate 85 million jobs — but create 97 million new ones, a net gain of 12 million.</p>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Amazon Warehouses</h4>\n    <p>Amazon has over 100,000 robots in its UK warehouses. When a customer places an order, the request is automatically passed to a robot. The robot follows digital patterns on the warehouse floor to locate the correct shelf and brings it to a human worker, who boxes and ships the item. Previously, human ''pickers'' walked many miles per day to do this manually.</p>\n    <p>Amazon''s UK sales rose by 51% to £19.4 billion in 2020. Employment actually grew by 3,000 workers despite the robot introduction. The robots enabled Prime next-day delivery. However, worker injury rates increased, and robots represent a breakdown risk.</p>\n    <p><strong>Takeaway:</strong> Amazon''s robots dramatically increased productivity and created a major competitive advantage (next-day delivery). But technology does not simply replace all workers — it often creates new roles and new problems.</p>\n    </div>", "question": "Approximately what percentage of robot use globally is in car manufacturing?", "options": ["15%", "35%", "65%", "90%"]}'::jsonb, '{"answer": 2, "explain": "Around 65% of all robot use is in car manufacturing — for welding, painting, and lifting. This makes car production the single biggest user of robotics globally."}'::jsonb),
('business:4-1-production-processes:learn:00cf0ad9', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Technology in Production", "reading": "<p>For evaluation questions, you must be able to weigh up <strong>both sides</strong> of using technology. Here is a comprehensive breakdown.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages of Technology</div>\n    <div class=\"pro-item\"><strong>Lower labour costs:</strong> Fewer workers are needed, reducing wage costs. Average costs of production fall, helping the business keep prices competitive in the market.</div>\n    <div class=\"pro-item\"><strong>Greater accuracy:</strong> Machines are more accurate than humans — improving product quality and reducing costly waste.</div>\n    <div class=\"pro-item\"><strong>Flexible production:</strong> Computer-controlled machines can be reprogrammed to produce a variety of products without restructuring the factory.</div>\n    <div class=\"pro-item\"><strong>Works 24/7:</strong> Machines work 24 hours a day, 7 days a week — unlike humans who need rest, take sick days, and go on holiday.</div>\n    <div class=\"pro-item\"><strong>Handles dangerous tasks:</strong> Machines can carry out dangerous or boring jobs that workers may be unable or unwilling to do, improving workplace safety.</div>\n    <div class=\"pro-item\"><strong>New products:</strong> New technology creates entirely new products and new markets (e.g., smartphones, tablets), growing the economy.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages of Technology</div>\n    <div class=\"con-item\"><strong>Redundancy costs:</strong> Workers may be made redundant when technology is introduced, resulting in short-term redundancy payments which add to costs.</div>\n    <div class=\"con-item\"><strong>Skilled recruitment:</strong> New skilled workers to manage the technology may need to be recruited. These workers are in high demand and may command large salaries.</div>\n    <div class=\"con-item\"><strong>Training costs:</strong> Existing workers may need retraining to use new technology — an additional business expense.</div>\n    <div class=\"con-item\"><strong>Breakdown risk:</strong> Machines can break down, disrupting production — especially serious in flow production where one fault halts the entire line.</div>\n    <div class=\"con-item\"><strong>High initial cost:</strong> Buying and financing new technology is expensive. The upfront investment may take many years to recoup.</div>\n    <div class=\"con-item\"><strong>Customer and data concerns:</strong> Customers sometimes dislike automated systems (e.g., automated phone lines). Where personal data is stored, there are also security risks.</div>\n    </div>\n    </div>", "question": "According to the World Economic Forum (2020), what was the predicted NET effect of technology on jobs by 2025?", "options": ["A net loss of 85 million jobs, with no new roles created to replace them", "A net gain of 12 million jobs, since 97 million are created and 85 million eliminated", "No overall change, since technology creates and destroys roughly equal numbers of jobs", "A net loss of 97 million jobs, since automation eliminates more roles than it creates"]}'::jsonb, '{"answer": 1, "explain": "The World Economic Forum predicted technology would eliminate 85 million jobs but create 97 million new ones — a net gain of 12 million. This is why ''technology eliminates all jobs'' is a misconception."}'::jsonb),
('business:4-1-production-processes:learn:0c262a0f', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the Right Production Method (Evaluation)", "reading": "<p>In an exam evaluation question, you must weigh up which production method is most appropriate. There is <strong>no single best method</strong> — it <em>depends on</em> the specific context of the business.</p>\n    <p><strong>Key factors that determine the right method:</strong></p>\n    <ul>\n      <li><strong>Volume of demand:</strong> High, consistent mass demand → flow. Unique, individual orders → job. Varied products in moderate quantities → batch.</li>\n      <li><strong>Price sensitivity:</strong> Customers wanting the lowest price → flow (economies of scale). Customers willing to pay a premium for uniqueness → job.</li>\n      <li><strong>Product type:</strong> Identical standardised products suit flow; varied or unique products suit job or batch.</li>\n      <li><strong>Capital investment available:</strong> Flow requires enormous set-up costs. Job requires skilled (expensive) labour. Batch sits in between.</li>\n      <li><strong>Flexibility required:</strong> Businesses needing to switch frequently between product types should use batch. Single high-volume product → flow.</li>\n    </ul>\n    <p><strong>Important evaluation point:</strong> Businesses can use a <em>combination</em> of methods. A caravan manufacturer might use job production to assemble each caravan but batch production to produce the shared components. Modern AI-driven machines are also blurring the lines between batch and flow, allowing variation in mass production.</p>\n    <p><strong>Useful \"it depends on...\" evaluation phrases:</strong></p>\n    <ul>\n      <li><em>\"This depends on whether the business can afford the high initial investment in an assembly line...\"</em></li>\n      <li><em>\"This depends on the level of demand — if the market grows significantly, flow production would lower unit costs and improve competitiveness...\"</em></li>\n      <li><em>\"This depends on whether customers in this market prioritise uniqueness and quality over low price...\"</em></li>\n      <li><em>\"This depends on whether the Montana Bakery wants to continue making the range of speciality breads it currently offers...\"</em></li>\n    </ul>", "question": "A bakery currently uses batch production for its speciality breads. A consultant recommends switching to flow production. What is the most important factor to consider before deciding?", "options": ["Whether the bakery owner personally prefers using machines rather than skilled staff", "Whether demand is high and consistent enough to justify the huge set-up cost of a flow line", "Whether rival bakeries have already switched over to using flow production themselves", "Flow production is always the right choice whenever a business wants to grow its output"]}'::jsonb, '{"answer": 1, "explain": "Flow production requires enormous capital investment and only makes sense when demand is very high and consistent for an identical product. A speciality bakery with varied, lower-volume orders may find batch production more appropriate — ''it depends on'' the nature and scale of demand."}'::jsonb),
('business:4-1-production-processes:misc:7dc232e3', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once a business chooses a production method, it is stuck with that method and cannot change.</p><p><strong>✅ The correct idea:</strong> Businesses can use a combination of methods simultaneously. A caravan manufacturer might use job production to assemble each caravan but batch production to make shared components. The method can also evolve as the business grows or demand changes.</p>", "question": "Can a business use more than one production method at the same time?", "options": ["No, a business must choose one method and keep it forever", "Yes, a caravan maker might use job for assembly, batch for parts", "Only if the business employs over 500 staff across its sites", "Only in manufacturing, never within a service-based business"]}'::jsonb, '{"answer": 1, "explain": "Businesses can and do combine methods — using job production for unique assemblies while using batch or flow for shared components within the same business."}'::jsonb),
('business:4-1-production-processes:misc:096cdcbf', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Job production is only suitable for small businesses.</p><p><strong>✅ The correct idea:</strong> Job production is used by businesses of all sizes. The Crossrail project in London (one of Europe''s largest infrastructure projects), ship-building companies, and bespoke advertising agencies all use job production. Size is irrelevant — the method refers to making individual, unique products.</p>", "question": "Which of the following is an example of job production by a LARGE business?", "options": ["Heinz producing baked beans on a continuous assembly line", "Crown Paints switching between different paint colours", "The Crossrail project — a unique, one-off construction job", "Warburton''s making batches of different types of bread"]}'::jsonb, '{"answer": 2, "explain": "Crossrail is a massive infrastructure project involving thousands of workers — yet it is job production because it is a unique, one-off product. Job production is defined by uniqueness, not business size."}'::jsonb),
('business:4-1-production-processes:misc:2792411f', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Flow production workers are highly skilled.</p><p><strong>✅ The correct idea:</strong> Flow production workers typically carry out repetitive, specialised tasks on an assembly line and are generally not considered highly skilled. It is JOB production that requires skilled workers — craftspeople, architects, surgeons, etc. — which is why job production has higher labour costs.</p>", "question": "Which production method requires the most skilled workers, and why?", "options": ["Flow production, because operating an assembly line takes considerable technical skill", "Batch production, because switching between different products requires real expertise", "Job production, because each product is individually made to unique specifications", "All three methods need roughly the same level of skill from their workers"]}'::jsonb, '{"answer": 2, "explain": "Job production demands highly skilled labour — craftspeople, architects, surgeons — because each product must meet individual specifications. This is why job production has the highest labour costs."}'::jsonb),
('business:4-1-production-processes:misc:4a133201', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Technology always replaces all workers, resulting in zero employment.</p><p><strong>✅ The correct idea:</strong> Technology reduces the number of workers needed but rarely eliminates them entirely. It also creates new jobs. Amazon introduced 100,000+ robots in its warehouses, but UK employment at Amazon actually grew by 3,000 workers as sales increased — because robots created new demand and new roles.</p>", "question": "What actually happened to Amazon UK employment after it introduced over 100,000 robots into its warehouses?", "options": ["Employment fell to zero, since every worker was replaced by a robot", "Employment fell by 3,000 workers as robots took over most warehouse roles", "Employment grew by 3,000 workers as sales and new roles increased", "Employment stayed exactly the same despite the introduction of the robots"]}'::jsonb, '{"answer": 2, "explain": "Despite introducing 100,000+ robots, Amazon UK employment grew by 3,000 workers — demonstrating that technology creates new jobs and roles even as it changes or eliminates others."}'::jsonb),
('business:4-1-production-processes:misc:5d5f0c0d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Batch production and flow production are basically the same — they both make lots of products.</p><p><strong>✅ The correct idea:</strong> They are fundamentally different. Batch makes a group of one type of product, then stops and switches to a different type. Flow makes the same product continuously without ever stopping. Flow is for very high volumes of an identical product; batch allows product variety through switching.</p>", "question": "What is the fundamental difference between batch and flow production?", "options": ["Batch relies mainly on machines, flow relies only on workers", "Batch makes a group then switches; flow never stops", "Flow production is always cheaper to run than batch", "Batch production can only ever be used by small firms"]}'::jsonb, '{"answer": 1, "explain": "The defining difference is continuity and variety: batch production stops and switches between product types; flow production never stops and makes the same product continuously."}'::jsonb),
('business:4-1-production-processes:misc:4218a2d2', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Automation and robotics mean exactly the same thing.</p><p><strong>✅ The correct idea:</strong> Automation is the broader term — any computer-controlled production process. Robotics is a specific type of automation where programmable robots perform tasks. All robotics is automation, but not all automation involves robots (e.g., automated door sensors, online banking systems).</p>", "question": "A school system that automatically texts parents when their child is absent — is this automation, robotics, or neither?", "options": ["Robotics, because the system is controlled entirely by a computer program", "Automation, because it is computer-controlled but involves no physical robot", "Neither, because sending a text message is not really a business process", "Both, because automation and robotics describe exactly the same technology"]}'::jsonb, '{"answer": 1, "explain": "This is automation — a computer-controlled process running without human involvement — but not robotics, which specifically requires a programmable physical robot. Not all automation involves robots."}'::jsonb),
('business:4-1-production-processes:misc:493d4172', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 3-mark ''Analyse'' question, simply naming a benefit and writing a general explanation is enough for full marks.</p><p><strong>✅ The correct idea:</strong> For 3 marks (U + APP + AN), you must: (1) state the benefit/point clearly, (2) apply it to the specific business in the case study using evidence from the text, AND (3) explain the business impact (on costs, revenue, or competitiveness). Without the Application, you cannot score the Analysis mark.</p>", "question": "Why can''t you score the Analysis (AN) mark on a 3-mark question without first including Application (APP)?", "options": ["You can — Analysis marks are always awarded regardless", "Marks are awarded in sequence — link to the business first", "Because Analysis marks only exist on six-mark questions", "Because Application and Analysis count as the same mark"]}'::jsonb, '{"answer": 1, "explain": "The U → APP → AN chain is sequential — without linking your point to the case study business (APP), there is no foundation for the analysis mark. AN cannot be awarded without APP."}'::jsonb),
('business:4-1-production-processes:misc:516fb55d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Flow production always produces lower quality goods compared to job production.</p><p><strong>✅ The correct idea:</strong> Flow production CAN produce high-quality, consistent goods. Modern computer-controlled machines are highly accurate. Cars produced on assembly lines, for example, undergo rigorous quality checks. The assumption that mass-produced automatically means low quality is outdated and incorrect.</p>", "question": "Does flow production necessarily produce lower quality goods than job production?", "options": ["Yes, because mass-produced goods are always lower quality than hand-made ones", "No, modern computer-controlled machines are accurate and give consistent quality", "Yes, but this drop in quality only happens within the food industry", "No, flow production always produces better quality than job production does"]}'::jsonb, '{"answer": 1, "explain": "Modern automated flow production lines can be extremely precise and consistent — cars from assembly lines undergo rigorous quality checks. The idea that mass-produced automatically equals low quality is outdated."}'::jsonb),
('business:4-1-production-processes:tips:ecb76846', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n          <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly <strong>one correct point</strong>. No explanation. No examples. No paragraphs.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific point = 1 mark ✅</li>\n            <li>A vague, general point = 0 marks ❌</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"Flow production is when things are made.\"</em><br/>\n          Too vague — doesn''t identify a specific characteristic of flow production.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br/>\n          <em>\"Goods are produced continuously using an assembly line.\"</em><br/>\n          Specific, precise, and directly answers the question.</p>\n    \n          <p><strong>⚠️ Examiner Warning:</strong> The OCR examiners noted that saying flow production is \"faster\" will NOT be rewarded — this depends on what is being produced and is not a specific characteristic. Always be precise: say \"uses an assembly line,\" \"continuous production,\" or \"low unit costs per product.\"</p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a full paragraph for a 1-mark question. Every extra sentence you write here is wasted time you need for the higher-mark questions.</p>\n        ", "question": "Why does the answer ''flow production is faster'' NOT score a mark on a 1-mark ''Identify a characteristic of flow production'' question?", "options": ["Because speed is never something examiners consider relevant to production", "Because speed depends on what is made and isn''t a fixed characteristic of flow", "Because only batch production can accurately be described as being faster", "Because the examiner actually accepts the word ''faster'' for full marks"]}'::jsonb, '{"answer": 1, "explain": "OCR examiners specifically flagged this — ''faster'' is relative and context-dependent, not a specific characteristic of flow production. Precise answers like ''uses an assembly line'' or ''produces continuously'' are required."}'::jsonb),
('business:4-1-production-processes:tips:2f7788cd', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Name It + Explain It", "reading": "\n          <p>A 2-mark <strong>''Explain''</strong> question needs two things: <strong>identify</strong> the concept AND <strong>explain</strong> what it means or how it works.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li><strong>Mark 1 (Knowledge):</strong> Name the production process or concept.</li>\n            <li><strong>Mark 2 (Understanding):</strong> Explain what it involves or how it works.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n          <em>\"Batch production.\"</em><br/>\n          Named it but failed to explain it — only 1 mark.</p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br/>\n          <em>\"Batch production (1), which is when a group of similar products are made together before production switches to a different type of product (1).\"</em></p>\n    \n          <p><strong>⚠️ Critical Examiner Warning:</strong> The OCR examiner noted that some candidates explained the process without naming it — and scored ZERO. Always NAME the concept first, then explain it.</p>\n    \n          <p><strong>⚠️ Application Warning:</strong> For a 2-mark ''Explain one way technology might affect production'' question, you MUST apply your point to the specific business. Answers about selling online or marketing when the question asks about <em>production</em> scored zero — always re-read the question carefully.</p>\n        ", "question": "Which answer would score 2 marks for ''Explain what is meant by batch production''?", "options": ["\"Batch production happens in factories that make one product.\"", "\"Batch production is when products are made quickly in bulk.\"", "\"Batch (1 mark), made as a group before switching product (1 mark).\"", "\"Batch production makes lots of products, which is good for business.\""]}'::jsonb, '{"answer": 2, "explain": "A 2-mark Explain answer needs the name (1 mark) and an accurate explanation of how it works (1 mark). Vague statements about ''large quantities'' or ''good for businesses'' do not explain the defining characteristic of batch production."}'::jsonb),
('business:4-1-production-processes:tips:17865726', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n          <p>A 3-mark <strong>''Analyse''</strong> question has a strict formula. You <strong>cannot</strong> score Application without Understanding. You <strong>cannot</strong> score Analysis without Application.</p>\n    \n          <p><strong>The 3-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback in general terms.<br/><em>\"Batch production allows a business to meet the needs of different customers...\"</em></li>\n            <li><strong>Step 2 — Application (APP):</strong> Link it specifically to the case study business using a fact from the text.<br/><em>\"...Pukka Pies produces different flavours of pies — steak, chicken balti, chicken and mushroom...\"</em></li>\n            <li><strong>Step 3 — Analysis (AN):</strong> State the business-facing impact — on costs, revenue, or competitiveness.<br/><em>\"...This allows different standardised products to be made to satisfy a wide range of customers, helping Pukka Pies grow its revenue.\"</em></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n          <em>\"Batch production is good because it makes more products.\"</em><br/>\n          No application to the business, no business impact — 1 mark at best.</p>\n    \n          <p><strong>✅ Good Answer (3 marks):</strong><br/>\n          <em>\"Each batch of pies can be made to match a specific order (U) for each different flavour of pie Pukka Pies produces (APP). This allows standardised products to be made to satisfy a range of customers, helping Pukka Pies increase its sales across its 4,000 outlets (AN).\"</em></p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about batch production. The examiner specifically noted that analysis must be about specific benefits of the production process — not generic outcomes like \"higher sales\" without explanation.</p>\n    \n          <p><strong>⚠️ The \"So What?\" Rule:</strong> Keep asking \"So what?\" until you reach a bottom-line business impact.<br/>\n          \"Automation reduces the number of workers needed.\" → So what? → \"This lowers wage costs.\" → So what? → \"This reduces average costs, allowing JLR to price its cars more competitively and increase profit margins.\" Now you have AN.</p>\n        ", "question": "Complete the analysis chain for JLR: ''Automation reduces the number of workers needed (U) → JLR''s factories use robots for welding and painting (APP) → ...''", "options": ["→ ''This means JLR has installed several new welding robots.''", "→ ''This lowers JLR''s wage costs, boosting its competitiveness (AN).''", "→ ''This means the workers at JLR''s factories feel much happier.''", "→ ''This shows JLR is a large car manufacturer based in the UK.''"]}'::jsonb, '{"answer": 1, "explain": "The Analysis mark requires a specific bottom-line business impact — reduced costs, improved competitiveness, higher revenue or profit. Simply restating what happens is not analysis."}'::jsonb),
('business:4-1-production-processes:tips:2f7d304e', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Points — 6 marks — Two 3-Mark Answers Written Back to Back", "reading": "\n          <p>A 6-mark <strong>''Analyse two...''</strong> question is simply <strong>two 3-mark analyses written consecutively</strong>. Use the exact same U → APP → AN formula for each point.</p>\n    \n          <p><strong>Structure:</strong></p>\n          <ul>\n            <li><strong>Point 1:</strong> U (state the advantage) → APP (link to the business using case study evidence) → AN (business-facing impact)</li>\n            <li><strong>Point 2:</strong> U (state the second advantage) → APP (link to the business again) → AN (different business impact)</li>\n          </ul>\n    \n          <p><strong>⚠️ DO NOT write a conclusion</strong> — there are zero marks available for evaluation in a 6-mark ''Analyse'' question. Every sentence must be U, APP, or AN.</p>\n    \n          <p><strong>Useful sentence starters:</strong></p>\n          <ul>\n            <li><em>\"Automation will [benefit] because...\"</em> (U)</li>\n            <li><em>\"In the case of JLR, this means...\"</em> or <em>\"As stated in the text, JLR...\"</em> (APP)</li>\n            <li><em>\"As a result, JLR will [lower costs / increase revenue / be more competitive]...\"</em> (AN)</li>\n          </ul>\n    \n          <p><strong>Exemplar (JLR, Advantage 1):</strong><br/>\n          <em>\"Automation will increase the number of cars JLR can produce (U). Machines can work 24/7, unlike human workers, meaning more cars move along the production line at JLR''s factories (APP). This should increase JLR''s total sales revenue and help it compete more effectively with BMW and Mercedes (AN).\"</em></p>\n        ", "question": "Should you write a conclusion or evaluation at the end of a 6-mark ''Analyse two advantages'' question?", "options": ["Yes, because a strong conclusion always improves the quality of the answer", "No, there are no evaluation marks here; every sentence must be U, APP or AN", "Yes, but the conclusion should be limited to a single short sentence", "Only if you manage to finish both analysis points well ahead of time"]}'::jsonb, '{"answer": 1, "explain": "A 6-mark Analyse question has no evaluation marks — writing a conclusion wastes time and scores nothing. Every sentence must directly contribute to one of the two U → APP → AN chains."}'::jsonb),
('business:4-1-production-processes:tips:90ad664a', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate / Recommend — 3 marks (AO3b) — Judgement + Reason + Context", "reading": "\n          <p>A 3-mark <strong>''Recommend'' or ''Evaluate''</strong> question (AO3b only) does NOT reward more analysis. It rewards a <strong>justified, contextual judgement</strong>.</p>\n    \n          <p><strong>The 3-Part Formula:</strong></p>\n          <ul>\n            <li><strong>Judgement (1 mark):</strong> Make a clear decision — yes/no, method A or B.<br/><em>\"The Montana Bakery should switch to flow production...\"</em></li>\n            <li><strong>Justification (1 mark):</strong> Give a reason that weighs up the decision.<br/><em>\"...because the cost savings it is likely to make are more important than any loss of perceived quality...\"</em></li>\n            <li><strong>Context (1 mark):</strong> Use specific information from the case study.<br/><em>\"...in a competitive market for bread where customers often buy the cheapest option.\"</em></li>\n          </ul>\n    \n          <p><strong>Power Phrase:</strong> Use \"it depends on...\" to show sophisticated evaluation:<br/>\n          <em>\"It depends on whether Montana Bakery wishes to continue making the range of speciality breads it currently supplies, as flow production may reduce their perceived uniqueness and lead M&S to lose confidence in the supplier.\"</em></p>\n    \n          <p><strong>❌ Common Mistake:</strong> Simply repeating the analysis points from the previous question does NOT earn evaluation marks. The evaluation must weigh up, make a decision, and say something NEW about whether it is worthwhile.</p>\n    \n          <p><strong>⚠️ Examiner Note:</strong> Both judgements (switch / don''t switch; use robots / don''t use robots) are perfectly valid in the exam — what matters is your contextual justification, not which side you pick.</p>\n        ", "question": "What are the THREE parts required for a full 3-mark Recommend/Evaluate answer?", "options": ["Three separate advantages of whichever production method has been chosen", "A clear judgement, a justification for it, and context from the case study", "A definition of the term, one advantage, and one matching disadvantage", "Two full paragraphs of analysis followed by a short closing summary"]}'::jsonb, '{"answer": 1, "explain": "A 3-mark Recommend answer needs: (1) a clear decision, (2) a reason that weighs up the options, and (3) specific context from the case study. Without all three, you will drop marks."}'::jsonb),
('business:4-1-production-processes:tips:076ab179', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks (APP + AN + EVAL) — Build the Case, Then Make the Call", "reading": "\n          <p>A 7-mark evaluation question (e.g., the Barclays question) awards marks for: <strong>Application (up to 2)</strong> + <strong>Analysis (up to 2)</strong> + <strong>Evaluation (up to 3)</strong>. There are NO knowledge marks — start with application immediately.</p>\n    \n          <p><strong>Four-Paragraph Structure:</strong></p>\n          <ul>\n            <li><strong>Paragraph 1 — Point 1 with Application:</strong><br/><em>\"By investing in online banking, Barclays is likely to gain more UK customers. As shown in Fig. 1, 75% of UK customers now use online banking...\"</em> (APP)</li>\n            <li><strong>Paragraph 2 — Analysis of Point 1:</strong><br/><em>\"...This means Barclays can earn more revenue from new accounts and transaction fees, improving its overall profit margins.\"</em> (AN)</li>\n            <li><strong>Paragraph 3 — Counter-point with Application:</strong><br/><em>\"However, all major competitor banks will have made similar investments in online banking, so Barclays may need to spend even more to maintain a competitive advantage...\"</em> (APP + AN)</li>\n            <li><strong>Paragraph 4 — Evaluation (3 parts: Decision + Context + Impact/Reasoning):</strong><br/><em>\"Overall, the investment is likely to benefit Barclays [Decision], given that 75% of its 24 million customers already use online banking [Context]. The cost savings from reducing branch staff will likely outweigh implementation costs in the long run [Reasoning].\"</em></li>\n          </ul>\n    \n          <p><strong>⚠️ Evaluation Warning:</strong> For the full 3 evaluation marks, your conclusion MUST be contextual — referring to specific facts from the case study. A generic conclusion (\"Technology is good for businesses\") scores 0 evaluation marks.</p>\n    \n          <p><strong>🚫 Customer-Only Impacts:</strong> The OCR examiner explicitly states \"No reward for answers which only consider impacts on the customer.\" Your analysis and evaluation MUST focus on the impact on the BUSINESS — costs, revenue, profit, reputation, and competitiveness.</p>\n        ", "question": "Why does a 7-mark evaluate question award NO knowledge marks, and what should your first sentence do instead?", "options": ["Because knowledge of methods isn''t tested at GCSE level at all", "All marks are for APP, AN and EVAL, so start by applying a point", "Because you should open with a definition to show knowledge", "Because knowledge marks are hidden within the Application marks"]}'::jsonb, '{"answer": 1, "explain": "A 7-mark evaluate question rewards APP (up to 2), AN (up to 2) and EVAL (up to 3) — there are zero knowledge marks. Opening with a definition wastes precious marks; start immediately with application to the case study business."}'::jsonb),
