('business:4-1-production-processes:match:4d989d71', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Job Production”?", "options": ["The process of production where one type of product is made and then production is switched to make a different product.", "Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The process of production where products are made individually."]}'::jsonb, '{"answer": 3, "explain": "“Job Production” means: The process of production where products are made individually."}'::jsonb),
('business:4-1-production-processes:match:744417ce', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Batch Production”?", "options": ["Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The process of production where one type of product is made and then production is switched to make a different product.", "The use of robots in the process of production."]}'::jsonb, '{"answer": 2, "explain": "“Batch Production” means: The process of production where one type of product is made and then production is switched to make a different product."}'::jsonb),
('business:4-1-production-processes:match:14686a23', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Flow Production”?", "options": ["Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "The use of robots in the process of production.", "A product made to the exact individual specification of a customer — unique to that person."]}'::jsonb, '{"answer": 0, "explain": "“Flow Production” means: Production of one product that takes place continuously using a production or assembly line. Also called mass production."}'::jsonb),
('business:4-1-production-processes:match:7621268d', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Automation”?", "options": ["The use of robots in the process of production.", "A product made to the exact individual specification of a customer — unique to that person.", "A production process involving machinery that is not controlled by a person but usually controlled by a computer.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage."]}'::jsonb, '{"answer": 2, "explain": "“Automation” means: A production process involving machinery that is not controlled by a person but usually controlled by a computer."}'::jsonb),
('business:4-1-production-processes:match:d67fab5b', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Robotics”?", "options": ["A product made to the exact individual specification of a customer — unique to that person.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "The use of robots in the process of production.", "Reductions in the average cost per unit that a large business benefits from by producing in very large quantities."]}'::jsonb, '{"answer": 2, "explain": "“Robotics” means: The use of robots in the process of production."}'::jsonb),
('business:4-1-production-processes:match:0096a66a', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bespoke”?", "options": ["A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "A product made to the exact individual specification of a customer — unique to that person.", "When a worker loses their job because their role no longer exists, often because technology has replaced it."]}'::jsonb, '{"answer": 2, "explain": "“Bespoke” means: A product made to the exact individual specification of a customer — unique to that person."}'::jsonb),
('business:4-1-production-processes:match:e187fc06', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Assembly Line”?", "options": ["Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced."]}'::jsonb, '{"answer": 1, "explain": "“Assembly Line” means: A method used in flow production where a product moves along a conveyor belt and workers or machines complete different tasks at each stage."}'::jsonb),
('business:4-1-production-processes:match:f89e6f3b', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economies of Scale”?", "options": ["Reductions in the average cost per unit that a large business benefits from by producing in very large quantities.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line."]}'::jsonb, '{"answer": 0, "explain": "“Economies of Scale” means: Reductions in the average cost per unit that a large business benefits from by producing in very large quantities."}'::jsonb),
('business:4-1-production-processes:match:16229dbd', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Redundancy”?", "options": ["The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "When a worker loses their job because their role no longer exists, often because technology has replaced it.", "The three methods or processes of production: job, batch, and flow."]}'::jsonb, '{"answer": 2, "explain": "“Redundancy” means: When a worker loses their job because their role no longer exists, often because technology has replaced it."}'::jsonb),
('business:4-1-production-processes:match:fc7a8267', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unit Cost”?", "options": ["Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "The three methods or processes of production: job, batch, and flow.", "The cost of producing one item. Calculated by dividing total costs by the number of units produced.", "The process of production where products are made individually."]}'::jsonb, '{"answer": 2, "explain": "“Unit Cost” means: The cost of producing one item. Calculated by dividing total costs by the number of units produced."}'::jsonb),
('business:4-1-production-processes:match:37fe8025', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mass Production”?", "options": ["Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line.", "The three methods or processes of production: job, batch, and flow.", "The process of production where products are made individually.", "The process of production where one type of product is made and then production is switched to make a different product."]}'::jsonb, '{"answer": 0, "explain": "“Mass Production” means: Another term for flow production — producing very large quantities of a standardised product continuously on an assembly line."}'::jsonb),
('business:4-1-production-processes:match:40c763a0', 'business', 'business:4-1-production-processes', '4.1 Production Processes', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Production Processes”?", "options": ["The process of production where products are made individually.", "The process of production where one type of product is made and then production is switched to make a different product.", "Production of one product that takes place continuously using a production or assembly line. Also called mass production.", "The three methods or processes of production: job, batch, and flow."]}'::jsonb, '{"answer": 3, "explain": "“Production Processes” means: The three methods or processes of production: job, batch, and flow."}'::jsonb),
('business:4-2-quality-of-goods-services:exam:2b63e82f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which of the following would help Zayn deal with this problem?", "options": ["Giving a bonus to the employee who sews the most gloves each month", "Improving quality checks to ensure every glove heats up correctly", "Researching other types of heated clothing that the business could make", "Segmenting the market by age, gender and lifestyle"], "caseStudy": "Zayn is the owner of an established business that makes heated gloves. The business has recently experienced an increase in product returns.", "hint": "Product returns = a quality problem. Which option directly addresses why the gloves are being returned?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Correct Answer: B — Improving quality checks to ensure every glove heats up correctly</strong></p><p>An increase in returns means the product is failing to meet customer expectations. Improving quality checks addresses the root cause of the problem.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Bonus for most gloves sewn:</strong> Incentivising speed may actually worsen quality, as workers rush production to earn more. Does not address the heating fault.</li><li><strong>C — Researching other heated clothing:</strong> This is a product development strategy, not a solution to the current quality problem with the gloves.</li><li><strong>D — Market segmentation:</strong> This is a marketing activity. Segmenting the market does not fix the fault that is causing gloves to be returned.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:f1e3017f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Which of the following actions would help QT Homeware Ltd deal with this problem?", "options": ["Include a cloth to wipe up any leaks in the box of all new kettles", "Launch a promotional campaign in a housekeeping magazine", "Meet with production workers to discuss how to reduce costs", "Physically test every hundredth kettle to ensure it is watertight"], "caseStudy": "QT Homeware Ltd manufactures small kitchen appliances. The company has recently received a number of emails complaining that its kettles leak.", "hint": "The problem is that kettles are leaking — a quality problem. Which option actually fixes the quality of the product?", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO2 Problem Solving)</h5><p><strong>Correct Answer: D — Physically test every hundredth kettle to ensure it is watertight</strong></p><p>This is a quality control measure that directly addresses the manufacturing fault.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Include a cloth:</strong> This accepts the fault and asks customers to deal with it — it does not solve the quality problem.</li><li><strong>B — Promotional campaign:</strong> Marketing does not fix a manufacturing defect. It may actually damage the brand further if new customers receive leaking kettles.</li><li><strong>C — Meeting to reduce costs:</strong> Cost reduction is unrelated to solving the leaking kettle problem and may make quality worse if it means cutting corners.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:e86c12d8', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q6", "question": "The concept of ''quality'' requires a business to:", "options": ["Produce goods that are better than the competition", "Produce goods that are reasonably priced", "Provide services that are fit for purpose", "Provide services that are value for money"], "hint": "What is the official definition of quality? Think about what ''quality'' actually means in a business context.", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: C — Provide services that are fit for purpose</strong></p><p>\"Fit for purpose\" is the core definition of quality — a product or service meets its intended function and the expectations of the customer.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Better than competition:</strong> Quality does not require being better than competitors — just meeting customer expectations at the required standard.</li><li><strong>B — Reasonably priced:</strong> Price is not part of the definition of quality. A cheap product can be quality; an expensive one can fail to be quality.</li><li><strong>D — Value for money:</strong> Value for money is a pricing/marketing concept. Quality means fit for purpose, not necessarily that the customer paid a fair price.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:d84e9287', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of the following would be an example of a quality assurance activity for a car manufacturer?", "options": ["Driving every tenth car to test that the brakes are working correctly", "Holding a meeting with production operatives on how to improve the manufacturing process", "Increasing the amount of money that the operations function can spend", "Visually inspecting two cars of each colour for defects in the paintwork"], "hint": "Quality assurance involves all workers improving quality together — it is not about inspecting finished products.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: B — Holding a meeting with production operatives on how to improve the manufacturing process</strong></p><p>Quality assurance involves all workers in a whole-business approach to quality. Meetings where production workers suggest improvements is a classic QA activity.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Driving every tenth car:</strong> This is quality CONTROL — sampling finished goods to inspect them.</li><li><strong>C — Increasing budget:</strong> This is a financial/resource decision, not a quality method.</li><li><strong>D — Visually inspecting two cars:</strong> This is quality CONTROL — inspecting a sample of finished goods for defects.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-2-quality-of-goods-services:exam:205712cd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'exam', 'mcq', 1, '{"num": "Q9", "question": "The concept of ''quality'' refers to making products:", "options": ["By hand", "Of a satisfactory standard", "That are better than the leading brand", "To the highest possible specification"], "hint": "What does the official definition of quality say? Think about fit for purpose and meeting customer expectations.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: B — Of a satisfactory standard</strong></p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — By hand:</strong> The method of production (hand-made vs machine-made) does not determine quality. A machine-made product can absolutely be quality if it is fit for purpose.</li><li><strong>C — Better than the leading brand:</strong> Quality means meeting expectations, not surpassing the market leader.</li><li><strong>D — Highest possible specification:</strong> Quality does not require the highest specification — only a satisfactory one that meets what the customer expected for that product and price.</li></ul></div>", "modelAnswer": ""}'::jsonb)
